import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function UsrProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch((err) => console.log(err));
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">
        <div className="backdrop-blur-lg bg-white/30 p-6 rounded-xl shadow-lg text-gray-700">
          Loading profile...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200 p-6">

      <div className="backdrop-blur-xl bg-white/30 border border-white/40 shadow-2xl rounded-2xl p-8 w-full w-[60vw]">

        {/* EDIT MODAL */}
        {showEditProfile && (
          <EditProfile closeModal={() => setShowEditProfile(false)} />
        )}

        {/* PROFILE IMAGE */}
        <div className="text-center">
          <div className="relative inline-block">
            <img
              src={
                user.profileImage ||
                `https://ui-avatars.com/api/?name=${user.username}`
              }
              alt="profile"
              className="w-28 h-28 rounded-full object-cover border-4 border-white shadow-lg"
            />

            <div className="absolute inset-0 rounded-full blur-xl bg-indigo-400 opacity-30"></div>
          </div>

          <h2 className="text-2xl font-bold mt-4 text-gray-800">
            {user.name}
          </h2>

          <p className="text-gray-600">{user.email}</p>

          <span className="inline-block mt-2 px-3 py-1 text-xs rounded-full bg-indigo-500 text-white shadow">
            {user.role}
          </span>
        </div>

        <div className="border-t w-[30vw] border-white/40 my-6"></div>

        {/* INFO */}
        <div className="items center space-y-3 text-sm text-gray-700">
          <div className="flex justify-between bg-white/20 p-2 rounded-lg">
            <span className="font-semibold">Username</span>
            <span>{user.username}</span>
          </div>

          <div className="flex justify-between bg-white/20 p-2 rounded-lg">
            <span className="font-semibold">Name</span>
            <span>{user.name}</span>
          </div>

          <div className="flex justify-between bg-white/20 p-2 rounded-lg">
            <span className="font-semibold">Role</span>
            <span>{user.role}</span>
          </div>
        </div>

        {/* BUTTONS */}
        <div className="mt-6 space-y-3">

          {/* OPEN MODAL */}
          <button
            onClick={() => setShowEditProfile(true)}
            className="w-full bg-gradient-to-r from-indigo-500 to-purple-600 text-white py-2 rounded-lg shadow-md hover:scale-105 transition"
          >
            Edit Profile
          </button>

          {/* LOGOUT */}
          <button
            onClick={() => {
              localStorage.clear();
              navigate("/");
              window.location.reload();
            }}
            className="w-full bg-red-500 text-white py-2 rounded-lg shadow-md hover:bg-red-600 hover:scale-105 transition"
          >
            Logout
          </button>

        </div>

      </div>
    </div>
  );
}
